import React from 'react';
import { useParams, Link } from 'react-router-dom';

const POSTS_DATA = {
  'how-to-build-a-visual-identity-that-stands-out': {
    title: 'How to build a visual identity that stands out',
    date: 'Mar 20, 2025',
    readTime: '5 min read',
    category: 'Branding',
    img: 'https://framerusercontent.com/images/2pZn1ac5q54fkkThIF56Vfou8.jpg',
    author: { name: 'Alex Carter', role: 'Founder & Creative Director', img: 'https://framerusercontent.com/images/mJOEscaN4cJv2tpti4OUyPBLdw.png?width=800&height=1200' },
    content: [
      { type: 'p', text: 'A visual identity is more than a logo. It\'s the entire visual language of your brand — the colours, typography, imagery, layout style, and the feeling it evokes at every touchpoint. Getting it right is one of the most important investments a business can make.' },
      { type: 'h2', text: 'Start with strategy, not aesthetics' },
      { type: 'p', text: 'Before opening a single design tool, ask yourself: what does your brand stand for? Who is your audience? What emotion should you evoke? These questions should drive every design decision.' },
    ],
  },
  'how-to-stay-relevant-in-a-fast-changing-digital-world': {
    title: 'How to stay relevant in a fast-changing digital world',
    date: 'Mar 13, 2025',
    readTime: '7 min read',
    category: 'Strategy',
    img: 'https://framerusercontent.com/images/xAmaN93UEGZxWaE2SAlY2hCRj08.jpeg',
    author: { name: 'Olivia Hart', role: 'Brand Strategist', img: 'https://framerusercontent.com/images/2UD1Kj1UE902txpUo5GdVYNTRTw.png?width=1200&height=735' },
    content: [
      { type: 'p', text: 'The digital landscape evolves at a pace that can feel overwhelming. Algorithms change, new platforms emerge, audience behaviours shift — and what worked brilliantly 18 months ago can suddenly feel dated and irrelevant.' },
      { type: 'h2', text: 'Build on timeless foundations' },
      { type: 'p', text: 'While tactics change, principles don\'t. A clear brand story, a well-defined audience, and genuine value proposition are timeless.' },
    ],
  },
};

export default function BlogDetail() {
  const { slug } = useParams();
  const post = POSTS_DATA[slug];

  if (!post) {
    return (
      <main className="not-found-page">
        <div className="container">
          <h1>Article not found</h1>
          <Link to="/blog" className="btn-primary">← Back to Blog</Link>
        </div>
      </main>
    );
  }

  return (
    <main className="blog-detail-page">
      <div className="bd-hero">
        <img src={post.img} alt={post.title} className="bd-hero-img" />
        <div className="bd-hero-overlay" />
        <div className="bd-hero-content container">
          <Link to="/blog" className="bd-back">← All Articles</Link>
          <div className="bd-meta">
            <span className="bd-category">{post.category}</span>
            <span>{post.readTime}</span>
            <span>{post.date}</span>
          </div>
          <h1 className="bd-title">{post.title}</h1>
        </div>
      </div>

      <div className="bd-body container">
        <aside className="bd-author">
          <img src={post.author.img} alt={post.author.name} className="bd-author-img" />
          <div>
            <p className="bd-author-name">{post.author.name}</p>
            <p className="bd-author-role">{post.author.role}</p>
          </div>
        </aside>

        <article className="bd-article">
          {post.content.map((block, i) => {
            if (block.type === 'h2') return <h2 key={i} className="bd-h2">{block.text}</h2>;
            return <p key={i} className="bd-p">{block.text}</p>;
          })}
        </article>
      </div>

      <div className="bd-footer container">
        <Link to="/blog" className="btn-outline">← Back to Blog</Link>
        <Link to="/contact" className="btn-primary">Work with us →</Link>
      </div>

      {/* CSS inside JSX */}
      <style>{`
        .blog-detail-page { padding-top: var(--nav-height, 80px); }

        .bd-hero {
          position: relative;
          height: 70vh;
          min-height: 480px;
          overflow: hidden;
          display: flex;
          align-items: flex-end;
        }
        .bd-hero-img {
          position: absolute;
          inset: 0;
          width: 100%;
          height: 100%;
          object-fit: cover;
          filter: brightness(0.35);
        }
        .bd-hero-overlay {
          position: absolute;
          inset: 0;
          background: linear-gradient(to top, rgba(10,10,10,0.9) 0%, transparent 60%);
        }
        .bd-hero-content {
          position: relative;
          z-index: 2;
          padding-bottom: 72px;
          max-width: 820px;
        }
        .bd-back {
          display: inline-block;
          font-size: 13px;
          color: rgba(240,236,230,0.5);
          margin-bottom: 20px;
        }
        .bd-meta {
          display: flex;
          gap: 12px;
          align-items: center;
          margin-bottom: 16px;
          font-size: 13px;
          color: rgba(240,236,230,0.55);
        }
        .bd-category {
          padding: 3px 8px;
          background: #333;
          color: #fff;
          border-radius: 2px;
          font-size: 11px;
          font-weight: 600;
        }
        .bd-title { font-size: clamp(28px, 4vw, 52px); font-weight: 800; }

        .bd-body { display: grid; grid-template-columns: 240px 1fr; gap: 80px; padding: 72px 32px; }
        .bd-author { position: sticky; top: 100px; display: flex; flex-direction: column; gap: 12px; }
        .bd-author-img { width: 64px; height: 64px; border-radius: 50%; object-fit: cover; }
        .bd-author-name { font-size: 15px; font-weight: 600; }
        .bd-author-role { font-size: 13px; color: #aaa; }
        .bd-article { max-width: 680px; }
        .bd-h2 { font-size: 26px; font-weight: 700; margin: 44px 0 16px; line-height: 1.25; }
        .bd-p { font-size: 17px; color: #ddd; line-height: 1.85; margin-bottom: 20px; }
        .bd-footer { display: flex; gap: 16px; padding: 64px 32px; }
        @media (max-width: 900px) { .bd-body { grid-template-columns: 1fr; gap: 48px; } .bd-author { position: static; flex-direction: row; align-items: center; } }
        @media (max-width: 600px) { .bd-footer { flex-direction: column; } }
      `}</style>
    </main>
  );
}
